// File: client/src/pages/Mindfulness.js
import React, { useState, useEffect } from 'react';

const Mindfulness = () => {
  const [breathingActive, setBreathingActive] = useState(false);
  const [breathPhase, setBreathPhase] = useState('inhale');
  const [breathCount, setBreathCount] = useState(0);
  const [timerActive, setTimerActive] = useState(false);
  const [timerSeconds, setTimerSeconds] = useState(300); // 5 minutes
  const [meditationPlayer, setMeditationPlayer] = useState(null);

  useEffect(() => {
    let breathingInterval;
    if (breathingActive) {
      breathingInterval = setInterval(() => {
        setBreathPhase(prev => {
          if (prev === 'inhale') {
            return 'hold';
          } else if (prev === 'hold') {
            return 'exhale';
          } else {
            setBreathCount(prev => prev + 1);
            return 'inhale';
          }
        });
      }, 4000); // 4 seconds for each phase
    }

    return () => clearInterval(breathingInterval);
  }, [breathingActive]);

  useEffect(() => {
    let timerInterval;
    if (timerActive && timerSeconds > 0) {
      timerInterval = setInterval(() => {
        setTimerSeconds(prev => prev - 1);
      }, 1000);
    } else if (timerSeconds === 0) {
      setTimerActive(false);
    }

    return () => clearInterval(timerInterval);
  }, [timerActive, timerSeconds]);

  const startBreathing = () => {
    setBreathingActive(true);
    setBreathPhase('inhale');
    setBreathCount(0);
  };

  const stopBreathing = () => {
    setBreathingActive(false);
  };

  const startTimer = () => {
    setTimerActive(true);
  };

  const pauseTimer = () => {
    setTimerActive(false);
  };

  const resetTimer = () => {
    setTimerActive(false);
    setTimerSeconds(300);
  };

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const meditations = [
    {
      id: 1,
      title: '5-Minute Breathing Meditation',
      duration: '5 min',
      description: 'A short guided meditation to center yourself and focus on your breath.',
      url: '#'
    },
    {
      id: 2,
      title: 'Body Scan Relaxation',
      duration: '10 min',
